public class Main {
	public static void main(String[] args) throws IOException {
		new Thread(null, new Runnable() {
			public void run() {
				try {
					long prevTime = System.currentTimeMillis();
					new Main().run();
					System.err.println("Total time: "
							+ (System.currentTimeMillis() - prevTime) + " ms");
					System.err.println("Memory status: " + memoryStatus());
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
		}, "1", 1L << 24).start();
	}

	void run() throws IOException {
		in = new BufferedReader(new InputStreamReader(System.in));
		out = new PrintWriter(System.out);
		Object o = solve();
		if (o != null)
			out.println(o);
		out.close();
		in.close();
	}

	int n;
	Point[] ps;
	int[] dp;

	private Object solve() throws IOException {
		int o_x = ni();
		int o_y = ni();

		n = ni();
		ps = new Point[n];
		for (int i = 0; i < n; i++)
			ps[i] = new Point(ni() - o_x, ni() - o_y);

		dp = new int[1 << n];
		Arrays.fill(dp, Integer.MAX_VALUE);
		dp[0] = 0;
		int[] path_x = new int[1 << n];
		int[] path_y = new int[1 << n];

		for (int mask = 1; mask < (1 << n); mask++) {
			int i = min(mask);
			int min_val = dp[mask - (1 << i)] + 2 * ps[i].norm;
			if (min_val < dp[mask]) {
				dp[mask] = min_val;
				path_x[mask] = i;
				path_y[mask] = i;

			}
			for (int j = i + 1; j < n; j++)
				if ((mask & (1 << j)) != 0) {
					int newMask = mask - (1 << i) - (1 << j);
					int val = dp[newMask] + ps[i].norm + ps[j].norm
							+ ps[i].dist(ps[j]);
					if (val < dp[mask]) {
						dp[mask] = val;
						path_x[mask] = i;
						path_x[mask] = j;

					}
				}
		}
		pln(dp[(1 << n) - 1]);

		int maskPath = (1 << n) - 1;
		LinkedList<Long> list = new LinkedList<Long>();
		while (maskPath != 0) {
			long x = path_x[maskPath];
			long y = path_y[maskPath];

			list.addFirst(0L);
			list.addFirst(y + 1);
			maskPath -= (1 << y);
			if (x != y) {
				list.addFirst(x + 1);
				maskPath -= 1 << x;
			}
		}
		list.addFirst(0L);
		show(list);
		return null;
	}

	private int min(int mask) {
		int ret = 0;
		while (mask % 2 == 0) {
			mask /= 2;
			ret++;
		}
		return ret;
	}

	private void show(LinkedList<Long> list) {
		int index = 0;
		for (long a : list) {
			if (index == 0) {
				p(a);
			} else {
				p(" " + a);
			}
			index++;
		}
		pln();
	}

