		int norm;

		public Point(int x, int y) {
			this.x = x;
			this.y = y;
			this.norm = x * x + y * y;
		}

		public int dist(Point other) {
			int dx = (x - other.x);
			int dy = (y - other.y);

			return dx * dx + dy * dy;
		}

