	void solve() throws IOException{
		Point bag = readPoint();

		int n = readInt();

		Point[] points = new Point[n];

		for (int i = 0; i < n; ++i){
			points[i] = readPoint();
		}

		int[] dist = new int[n];
		for (int i = 0; i < n; ++i){
			int dx = points[i].x - bag.x;
			int dy = points[i].y - bag.y;

			dist[i] = dx * dx + dy * dy;
		}

		int[][] d = new int[n][n];
		for (int i = 0; i < n; ++i){
			for (int j = 0; j < n; ++j){
				int dx = points[i].x - points[j].x;
				int dy = points[i].y - points[j].y;

				d[i][j] = dx * dx + dy * dy;
				d[i][j] += dist[i] + dist[j];
			}
		}

		int[] singleMasks = new int[n];
		for (int i = 0; i < n; ++i){
			singleMasks[i] = (1 << i);
		}

		int[][] doubleMasks = new int[n][n];
		for (int i = 0; i < n; ++i){
			for (int j = 0; j < n; ++j){
				doubleMasks[i][j] = (singleMasks[i] | singleMasks[j]);
			}
		}

		int lim = (1 << n);
		int[] dp = new int[lim];

		Arrays.fill(dp, Integer.MAX_VALUE);
		dp[0] = 0;

		int[] p = new int[lim];
		Arrays.fill(p, -1);

		for (int mask = 0; mask < lim; ++mask){
			if (dp[mask] == Integer.MAX_VALUE){
				continue;
			}

			int minBit = -1;

			for (int bit = 0; bit < n; ++bit){
				if (checkBit(mask, bit)) continue;

				if (minBit == -1 || (dist[minBit] > dist[bit])){
					minBit = bit;
				}
			}

			if (minBit == -1){
				continue;
			}

			for (int bit = 0; bit < n; ++bit){
				if (checkBit(mask, bit)) continue;

				int newMask = (mask | (1 << minBit) | (1 << bit));

				if (dp[newMask] > dp[mask] + d[minBit][bit]){
					dp[newMask] = dp[mask] + d[minBit][bit];
					p[newMask] = minBit * n + bit;
				}
			}
		}

		out.println(dp[lim-1]);

		int curMask = lim - 1;
		while (p[curMask] != -1){
			out.print("0 ");

			int first = p[curMask] / n;
			int second = p[curMask] % n;

			out.print((first + 1) + " ");
			curMask ^= (1 << first);

			if (first != second){
				out.print((second + 1) + " ");
				curMask ^= (1 << second);
			}
		}

		out.println("0");
	}

	private boolean checkBit(int mask, int bitNumber) {
		return (mask & (1 << bitNumber)) != 0;
	}

	boolean checkMask(int mask, int innerMask){
		return (mask & innerMask) == innerMask;
	}
}

