public class CF {

	void realSolve() {
		int n = in.nextInt();
		int m = in.nextInt();
		boolean[][] f = new boolean[n][n];
		for (int i = 0; i < m; i++) {
			int fr = in.nextInt() - 1;
			int to = in.nextInt() - 1;
			f[fr][to] = f[to][fr] = true;
		}
		long[][] dp = new long[n][1 << n];
		for (int i = 0; i < n; i++)
			dp[i][1 << i] = 1;
		long res = 0;
		int[] len = new int[n + 1];
		for (int st = 0; st < 1 << n; st++) {
			int from = Integer.lowestOneBit(st);
			for (int i =0; i < n;i++)
				if (((1<<i) & st) != 0) {
					from =i;
					break;
				}
			for (int to = 0; to < n; to++)
				if (dp[to][st] != 0)
					for (int next = from; next < n; next++)
						if (f[to][next]
								&& ((((1 << next) & st) == 0) || next == from))
							if (next == from) {
								if (Integer.bitCount(st) > 2) {
									res += dp[to][st];
									len[Integer.bitCount(st)] += dp[to][st];
								}
							} else {
								dp[next][st | (1 << next)] += dp[to][st];
							}
		}
		out.println(res / 2);
	}

