//        int numTests = in.readInt();
//        for (int testNumber = 0; testNumber < numTests; testNumber++) {
//        }
		n = in.readInt();
		m = in.readInt();
		e = new boolean[n][n];
		for (int i = 0; i < m; i++) {
			int a = in.readInt() - 1;
			int b = in.readInt() - 1;
			e[a][b] = e[b][a] = true;
		}
//		n = 19;
//		e = new boolean[n][n];
//		for (int i = 0; i < n; i++) {
//			for (int j = 0; j < n; j++)
//				e[i][j] = i != j;
//		}
		int msk = (1 << n) - 1;
		qp = new long[n - 1][1 << (n - 1)];
		long ans = 0;
		for (int i = n - 1; i >= 0; i--) {
			msk -= (1 << i);
			for (int k = 0; k < i; k++)
				Arrays.fill(qp[k], 0, 1 << i, -1);
			for (int j = 0; j < i; j++) {
				if (e[i][j]) {
					e[i][j] = e[j][i] = false;
					ans += go(j, msk - (1 << j), i);
					e[i][j] = e[j][i] = true;
				}
			}
		}
		out.println(ans / 2);
		out.close();
