	private long go(int v, int msk, int u) {
		if (qp[v][msk] != -1)
			return qp[v][msk];
		qp[v][msk] = 0;
		if (e[v][u])
			qp[v][msk] = 1;
		for (int i = 0; i < u; i++) {
			if (e[v][i] && ((msk >> i) & 1) != 0)
				qp[v][msk] += go(i, msk - (1 << i), u);
		}
		return qp[v][msk];
	}
