		// long time = System.currentTimeMillis();
		int n = nextInt();
		int m = nextInt();
		boolean[][] edges = new boolean[n][n];
		boolean[] edge = new boolean[(n << 5) | n];
		for (int i = 0; i < m; i++) {
			int x = nextInt() - 1;
			int y = nextInt() - 1;
			edges[x][y] = edges[y][x] = true;
			edge[(x << 5) | y] = edge[(y << 5) | x] = true;
		}
		long[][] dp = new long[n][1 << n];
		long ans = 0;
		for (int i = 0; i < n; i++) {
			for (int mask2 = 1; mask2 < 1 << (n - i - 1); ++mask2) {
				for (int j = i + 1; j < n; j++) {
					dp[j][mask2 << i << 1] = 0;
				}
			}
			for (int j = i + 1; j < n; j++) {
				if (edges[i][j]) {
					dp[j][1 << j] = 1;
				}
			}
			for (int mask2 = 1; mask2 < 1 << (n - i - 1); ++mask2) {
				int mask = (mask2 << i << 1);
				if ((mask & (mask - 1)) == 0) {
					continue;
				}
				for (int j = i + 1; j < n; j++) {
					if (((mask >> j) & 1) == 0) {
						continue;
					}
					dp[j][mask] = 0;
					for (int k = i + 1; k < n; k++) {
						if (((mask >> k) & 1) == 0 || !edge[(j << 5) | k]) {
							continue;
						}
						dp[j][mask] += dp[k][mask & ~(1 << j)];
					}
					if (edge[(i << 5) | j]) {
						ans += dp[j][mask];
					}
				}
			}
		}
//		if (n >= 3) {
//			if (edges[n - 3][n - 2] && edges[n - 3][n - 1]
//					&& edges[n - 2][n - 1]) {
//				ans += 2;
