					if((graph[u] & (1 << v)) != 0) 
						DP[mask][u] += DP[mask ^ (1 << u)][v];

				}
			}
		}

		long totalCycles = 0;
		for(int mask = 1 , end = 1 << V;mask < end;mask++) {
			if(Integer.bitCount(mask) >= 3) {
