class SimpleCycles implements Solver {
    public void solve(int testNumber, InputReader in, PrintWriter out) {
        int n = in.nextInt();
        int m = in.nextInt();
        boolean[][] g = new boolean[n][n];
        for (int i = 0; i < m; ++i) {
            int u = in.nextInt();
            int v = in.nextInt();
            --u;
            --v;
            g[u][v] = g[v][u] = true;
        }
        HashMap<Integer, Integer> pointer = new HashMap<Integer, Integer> () ;
        for (int i =0 ; i < n; ++i) {
            pointer.put(1 << i, i);
        }
        long[][] dm = new long[1 << n][n];
        for (int i = 0; i < n; ++i) {
            dm[1 << i][i] = 1;
        }
        for (int i = 0; i < (1 << n); ++i) {
            for (int j = 0; j < n; ++j) {
                if (dm[i][j] == 0) continue;
                int k = pointer.get(i - (i & (i - 1)));
                for (int u = k + 1; u < n; ++u) {
                    if (g[j][u] && (i & (1 << u)) == 0) {
                        dm[i | (1 << u)][u] += dm[i][j];
                    }
                }
            }
        }
        long res = 0;
        for (int i = 0; i < (1 << n); ++i) {
            for (int j = 0; j < n; ++j)
                if (Integer.bitCount(i) >= 3) {

                    int c = pointer.get(i - (i & (i - 1)));
                    if (g[c][j]) res += (long) dm[i][j];
                }
        }
        out.print(res / 2);
    }
}

