        }
        int all = (1 << n) - 1;
        for (int i = 0; i < n; i++) {
            int l = (1 << i);
            int left = all ^ (l - 1) ^ l;
            for (int j = left; j > 0; j = (j - 1) & left)
                if ((j & (j - 1)) != 0) {
                    dp[j | l][i] = 1;
                }
        }
        for (int i = (1 << n) - 1; i > 0; i--) {
            int last = i & -i;
