                if (((1 << j) == last && (i & (i - 1)) != 0)
                        || ((1 << j) & i) == 0)
                    continue;
                for (int k = 0; k < n; k++) {
                    if ((1 << k) >= last && ((1 << k) & g[j]) != 0
                            && ((1 << k) == last || ((1 << k) & i) == 0)) {
                        dp[i][j] += dp[i | (1 << k)][k];
                    }

                }
            }
        }
        long res = 0;
