			int v = sc.nextInt() - 1;
			int u = sc.nextInt() - 1;
			adjList[v].add(u);
			adjList[u].add(v);
		}
		out.print(Number_Of_Simple_Cycles());
		out.flush(); 
		out.close();
	}



