		boolean[][] arr = new boolean[n][n];
		for (int i = 0; i < m; i++) {
			int a = sc.nextInt();
			int b = sc.nextInt();
			arr[a - 1][b - 1] = true;
			arr[b - 1][a - 1] = true;
		}
		long[][] res = new long[n][1 << n];
		for (int mask = 1; mask < (1 << n); mask++) {
			int min = -1;
			for (int i = 0; i < n; i++) {
				if ((mask & (1 << i)) != 0) {
					if (min == -1) {
						min = i;
						if (mask == (1 << min))
							res[min][mask] = 1;
					}
					for (int j = min + 1; j < n; j++)
						if ((mask & (1 << j)) == 0 && arr[i][j]) {
							res[j][mask | (1 << j)] += res[i][mask];
						}
				}
			}
		}
		long r = 0;
		for (int mask = 1; mask < (1 << n); mask++)
			if (Integer.bitCount(mask) != 2)
				for (int j = 0; j < n; j++) {
					int i = 0;
					while ((mask & (1 << i)) == 0)
						i++;
					if (arr[i][j])
						r += res[j][mask];
				}
		System.out.println(r / 2);
	}
}

