            int f = in.nextInt() - 1;
            int t = in.nextInt() - 1;
            adj[f][t] = adj[t][f] = true;
        }

        boolean[] v = new boolean[1 << n];
        long res = 0;
        for (int f = 0; f < n; f++) {
