			int v = nextInt()-1;
			e[u][v] = true;
			e[v][u] = true;
			if (u < v) {
				f[bit(u)|bit(v)][v] = 1;
			}
			else {
				f[bit(v)|bit(u)][u] = 1;
			}
		}
		long answer = 0;
		for (int i = 1; i < (1<<n); ++i) {
			int start = 0;
			while (((1<<start)&i) == 0) {
				++start;
			}
			int s = bit(start);
			for (int nxt = start+1; nxt < n; ++nxt) {
				int b = bit(nxt);
				if ((b&i) > 0 && (b|s) != i) {
					if (e[start][nxt]) {
						answer += clc(i, nxt);
					}
				}
			}
		}
		writer.print(answer>>1);
	}

	long clc(int maska, int last) {
		if (f[maska][last] == -1) {
			int first = 0;
			while (((1<<first)&maska) == 0) {
				++first;
			}
			f[maska][last] = 0;
			for (int b = first+1; b < n; ++b) {
				if ((bit(b)&maska)>0) {
					if (e[b][last]) {
						f[maska][last] += clc(maska^bit(last), b);
					}
				}
			}		
		}
		return f[maska][last];
	}

	public static void main(String[] args) throws InterruptedException {
		 new Thread(null, new Runnable() {
            public void run() {
                new Main().run();
            }
	     }, 
