import java.util.*;
public class Fish {
	static double[][] prob;
	static double[] dp=new double[1<<19];
	static double pmove(int mask,int fish_to_kill,int n) {
		int count=0;
		for(int i=0;i<n;i++) {
			if((mask&(1<<i))!=0) {
				++count;
			}
		}
		long totalPairs=(count*(count-1))/2;
		double prob_die=0;
		for(int fish=0;fish<n;fish++) {
			if((mask&(1<<fish))!=0) {
				prob_die+=prob[fish][fish_to_kill];
			}
		}
		return prob_die/totalPairs;
	}

	static double solve(int mask,int n) {
		if(mask==((1<<n)-1)) {
			return 1;
		}
		if(dp[mask]>-0.9) {
			return dp[mask];
		}
		double ans=0;
		for(int fish=0;fish<n;fish++) {
			if((mask&(1<<fish))==0) {
				int prev_mask=mask|(1<<fish);
				ans+=pmove(prev_mask,fish,n)*solve(prev_mask,n);
			}
		}
		dp[mask]=ans;
		return dp[mask];

	}

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		Scanner sc=new Scanner(System.in);
		int n=sc.nextInt();
		prob=new double[n][n];
		for(int i=0;i<n;i++) {
			for(int j=0;j<n;j++) {
				prob[i][j]=sc.nextDouble();
			}
		}
		Arrays.fill(dp, -1);
		for(int i=0;i<n;i++) {

			System.out.print(String.format("%.06f", solve(1<<i,n))+" ");
		}

	}

}

import java.util.*;

public class cf16e {
	static int n;
	static double[][] prob;
	static double[] memo;
	public static void main(String[] args) {
		Scanner in = new Scanner(System.in);
		n = in.nextInt();
		prob = new double[n][n];
		memo = new double[1<<n];
		for(int i=0; i<n; i++)
			for(int j=0; j<n; j++)
				prob[i][j] = in.nextDouble();
		memo[(1<<n)-1] = 1;
		for(int k=(1<<n)-1; k>0; k--) {
			int numWays = Integer.bitCount(k);
			numWays = (numWays*(numWays-1))/2;
			for(int first = 0; first < n; first++) {
				if(!isSet(k,first)) continue;
				for(int second = first+1; second < n; second++) {
					if(!isSet(k,second)) continue;
					memo[reset(k,first)] += prob[second][first]*memo[k]/numWays;
					memo[reset(k,second)] += prob[first][second]*memo[k]/numWays;
				}
			}
		}
		for(int i=0; i<n; i++)
			System.out.printf("%.6f ", memo[set(0,i)]);
		System.out.println();
	}
	static boolean isSet(int x, int p) {
		return (x&(1<<p)) != 0;
	}
	static int set(int x, int p) {
		return x|(1<<p);
	}
	static int reset(int x, int p) {
		return x&~(1<<p);
	}
	static boolean isDone(int x) {
		return Integer.bitCount(x)==n-1;
	}
}

