class TaskE {

    private int n;
    private double[] dp;
    private double[][] p;

    public void solve(int testNumber, InputReader in, PrintWriter out) {
        n = in.nextInt();
        p = new double[n][n];
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                p[i][j] = in.nextDouble();
            }
        }
        dp = new double[1 << n];
        Arrays.fill(dp, -1);
        for (int i = 0; i < n; ++i) {
            out.printf("%.6f ", rec(1 << i));
        }
        out.println();
    }

    private double rec(int mask) {
        if (mask == (1 << n) - 1) return 1;
        if (dp[mask] > -0.5) return dp[mask];
        double res = 0;
        int nn = Integer.bitCount(mask);
        int total = (nn * (nn + 1)) / 2;
        for (int i = 0; i < n; ++i) if (BitUtils.checkBit(mask, i)) for (int j = 0; j < n; ++j) if (!BitUtils.checkBit(mask, j)) {
            res += rec(BitUtils.setBit(mask, j)) * p[i][j];
        }
        res /= total;
        dp[mask] = res;
        return res;
    }
}

