          if ((mask & (1 << j)) == 0)
            f[mask]+=doIt(mask|(1<<j))*a[i][j]/k;
    return f[mask]; 
  }
  private int getBits(int x){
    int cnt = 0;
    while(x > 0){
      x&=(x-1);
      cnt++;
    }
    return cnt+1;
  }

