public class A {

	static double[][] a;
	static int N;
	static double[] memo;

	static double dp(int alive)
	{
		int count = Integer.bitCount(alive);
		if(count == N)
			return 1;
		if(memo[alive] > -5)
			return memo[alive];

		double ret = 0;
		for(int j = 0; j < N; ++j)
			if((alive & (1<<j)) == 0)
				ret += die[j][alive | 1<<j] * dp(alive | 1<<j);			

		return memo[alive] = ret;
	}

	static double[][] die;
	static void f()
	{
		die = new double[N][1<<N];
		for(int i = 0; i < N; ++i)
			for(int j = 0; j < 1<<N; ++j)
			{
				int count = Integer.bitCount(j);
				if(count <= 1)
					continue;
				double prop = 1.0 / (count * (count - 1) >> 1);
				for(int k = 0; k < N; ++k)
					if((j & (1<<k)) != 0)
						die[i][j] += prop * a[k][i]; 
			}

	}

	public static void main(String[] args) throws IOException {

		Scanner sc = new Scanner(System.in);
		PrintWriter out = new PrintWriter(System.out);

		N = sc.nextInt();

		a = new double[N][N];
		for(int i = 0; i < N; ++i)
			for(int j = 0; j < N; ++j)
				a[i][j] = sc.nextDouble();
		memo = new double[1<<N];
		f();

		Arrays.fill(memo, -10);		
		for(int i = 0; i < N - 1; ++i)
			out.printf("%.8f ", dp(1 << i));
		out.printf("%.8f\n", dp(1 << N - 1));

		out.flush();
		out.close();
	}

