    static double[][] m;
    static double[] memo;

    static double solve(int mask) {
        if (memo[mask] != Double.POSITIVE_INFINITY) return memo[mask];
        if (mask == t-1) return memo[mask] = 1;

        int k = Integer.bitCount(mask);
