            for (int j = 0; j < n; j++){
                if ((i & (1 << j)) != 0) list.add(j);
            }
            double s = 0;
            for (int j = 0; j < list.size(); j++){
                s = 0;
                for (int k = 0; k < list.size(); k++){
                    s += a[list.get(k)][list.get(j)];
                }
                d[i ^ (1 << list.get(j))] += s * d[i] * 2 / list.size() / (list.size() - 1);
            }
        }
        for (int i = 0; i < n; i++){
            out.printf(Locale.US, "%.9f", d[1 << i]);
            out.print(" ");
        }
    }

