	private BasicInputOutput iohandler;
	private int n;
	private double[][] mat;
	private double[][] sum;
	private double[] dp;
	private int tolive;
	private void run()throws Exception
	{
		initialize();
		solve();
	}
	private void initialize() throws Exception
	{
		iohandler=new BasicInputOutput();
		n=iohandler.getNextInt();
		mat=new double[n][n];
		sum=new double[(1<<n)+10][n];
		dp=new double[1<<n];
		for(int i=0;i<n;i++) for(int j=0;j<n;j++)
		{
			mat[i][j]=iohandler.getNextDouble();
		}
	}
	private int bitCount(int mask)
	{
		int ret=0;
		while(mask>0) {
			ret++;
			mask&=(mask-1);
		}
		return ret;
	}
	private void solve() throws Exception
	{
		double[] ans=new double[n];
		int ub=1<<n;
		for(int i=1;i<ub;i++) {
			for(int j=0;j<n;j++) {
				sum[i][j]=0;
				for(int k=0;k<n;k++) if ((i&(1<<k))!=0) sum[i][j]+=mat[k][j];
				int cntbit=bitCount(i);
				if (cntbit>1)
				sum[i][j]/=((double)cntbit*(cntbit-1.))/2.;
			}
		}
		dp[ub-1]=1.;
		for(int mask=ub-1;mask>=1;mask--) {
			if (dp[mask]==0.) continue;
			for(int i=0;i<n;i++) {
				if ((mask&(1<<i))==0) continue;
				dp[mask-(1<<i)]+=sum[mask][i]*dp[mask];
			}
		}
		for(int i=0;i<n;i++)
		ans[i]=dp[1<<i];
		/*
		for(int i=0;i<n;i++)
		{
			for(int mask=1;mask<ub;mask++) {
				dp[mask]=0;
				if ((mask&(1<<i))==0) continue;
				if (bitCount(mask)==1)
				{
					dp[mask]=1.;
				} else
				for(int k=0;k<n;k++) {
					if ((mask&(1<<k))==0) continue;
					if (i==k) continue;
					dp[mask]+=sum[mask][k]*dp[mask-(1<<k)];
				}
			}
			ans[i]=dp[ub-1];
		}*/
		iohandler.write(ans[0]+"");
		for(int i=1;i<n;i++) iohandler.write(" "+ans[i]);
		iohandler.write("\n");
		iohandler.flush();
	}
}

import java.util.Arrays;
import java.util.Scanner;


public class Main {
    static double[] dp;
    static double[][] P;
    public static void main(String[] args) {
        Scanner r = new Scanner(System.in);

        int n = r.nextInt();

        double[][] g = new double[n][n];
        for(int i = 0; i < n; i++)
            for(int j = 0; j < n; j++)
                g[i][j] = r.nextDouble();

        dp = new double[1 << n];
        P = new double[1 << n][n];
        for(int mask = 0; mask < 1 << n; mask++){
            for(int d = 0; d < n; d++)if((mask & (1 << d)) == 0)
                for(int i = 0; i < n; i++)if((mask & (1 << i)) == 0){
                    if(i == d)continue;

                    P[mask][d] += g[i][d];
                }
        }

        for(int i = 0; i < n; i++){
            Arrays.fill(dp, -1);

            double res = go(i, 0, g, n, n);
            System.out.println(res);
        }
    }

    private static double go(int a, int v, double[][] g, int cnt, int n) {
        if(dp[v] != -1)return dp[v];

        if(cnt == 1){
            return 1;
        }else{
            double ret = 0;
            for(int d = 0; d < n; d++)if((v & (1 << d)) == 0 && d != a){
                double current =  P[v][d] * go(a, v | 1 << d, g, cnt-1, n);
                ret += current;
            }

            return dp[v] = ret/(cnt * (cnt-1) /2);
        }  
    }
}

