                int jPower = 1 << j;

                if ((mask & jPower) == jPower || i == j)
                    continue;

                // still alive
                totalProba += (matchProba * matrix[i][j] * fillDP(mask | jPower));
            }
        }

        return masks[mask] = totalProba;

    }
}

