class TaskE {
    public void solve(int testNumber, InputReader in, OutputWriter out) {
        int n = in.nextInt();
        double[][] probability = in.next2DDoubleArray(n, n);
        double[] dp = new double[1 << n];
        dp[dp.length - 1] = 1;
        for (int mask = (1 << n) - 1; mask >= 0; mask--) {
            int count = Integer.bitCount(mask);
            if (count <= 1) continue;
            double multi = 1. / calc(count);
            for (int i = 0; i < n; i++) {
                if (NumberUtils.checkBit(mask, i)) {
                    for (int j = i + 1; j < n; j++) {
                        if (NumberUtils.checkBit(mask, j)) {
                            // i eat j
                            dp[mask - (1 << j)] += multi * probability[i][j] * dp[mask];
                            // j eat i
                            dp[mask - (1 << i)] += multi * probability[j][i] * dp[mask];
                        }
                    }
                }
            }
        }
        double[] answer = new double[n];
        for (int i = 0; i < n; i++) {
            answer[i] = dp[1 << i];
        }
        out.printLine(ArrayUtils.asList(answer).toArray());
    }

    private static int calc(int x) {
        return x * (x - 1) / 2;
    }
}

class InputReader {

    private InputStream stream;
    private byte[] buf = new byte[1024];
    private int curChar;
    private int numChars;

    public InputReader(InputStream stream) {
        this.stream = stream;
    }

    public int read() {
        if (numChars == -1)
            throw new InputMismatchException();
        if (curChar >= numChars) {
            curChar = 0;
            try {
                numChars = stream.read(buf);
            } catch (IOException e) {
                throw new InputMismatchException();
            }
            if (numChars <= 0)
                return -1;
        }
        return buf[curChar++];
    }

    public int nextInt() {
        int c = read();
        while (isSpaceChar(c))
            c = read();
        int sgn = 1;
        if (c == '-') {
            sgn = -1;
            c = read();
        }
        int res = 0;
        do {
            if (c < '0' || c > '9')
                throw new InputMismatchException();
            res *= 10;
            res += c & 15;
            c = read();
        } while (!isSpaceChar(c));
        return res * sgn;
    }

    public static boolean isSpaceChar(int c) {
        return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
    }

    public double nextDouble() {
        int c = read();
        while (isSpaceChar(c))
            c = read();
        int sgn = 1;
        if (c == '-') {
            sgn = -1;
            c = read();
        }
        double res = 0;
        while (!isSpaceChar(c) && c != '.') {
            if (c == 'e' || c == 'E')
                return res * Math.pow(10, nextInt());
            if (c < '0' || c > '9')
                throw new InputMismatchException();
            res *= 10;
            res += c - '0';
            c = read();
        }
        if (c == '.') {
            c = read();
            double m = 1;
            while (!isSpaceChar(c)) {
                if (c == 'e' || c == 'E')
                    return res * Math.pow(10, nextInt());
                if (c < '0' || c > '9')
                    throw new InputMismatchException();
                m /= 10;
                res += (c - '0') * m;
                c = read();
            }
        }
        return res * sgn;
    }

    public double[] nextDoubleArray(int count) {
        double[] result = new double[count];
        for (int i = 0; i < count; i++) {
            result[i] = nextDouble();
        }
        return result;
    }

    public double[][] next2DDoubleArray(int n, int m) {
        double[][] result = new double[n][];
        for (int i = 0; i < n; i++) {
            result[i] = nextDoubleArray(m);
        }
        return result;
    }

    }

