			int prev = mask | (1 << eaten);
			if (prev != mask) {
				for (int eats = 0; eats < n; eats++) {
					if ((mask & (1 << eats)) != 0) {
						ans += a[eats][eaten] * p(prev);
					}
				}
			}
		}
		int bc = Integer.bitCount(mask);
		int norm = bc * (bc + 1) / 2;
		return p[mask] = ans / norm;
	}

