        for(int i = 0; i < n; ++i)
            for (int j = 0; j < n; ++j) {
                a[i][j] = nextDouble();
            }
        dm = new double[1 << n];
        fil = new boolean[1 << n];
        for(int i = 0; i < n; ++i) {
            out.print(brute((1 << i)) + " ");
        }
    }

    private double brute(int mask) {
        if (Integer.bitCount(mask) == n) return 1;
        if (fil[mask]) return dm[mask];
        int c = Integer.bitCount(mask);
        double res = 0;
        double p = 2.0 / (double) (c + 1) / (double)(c ) ;
        for(int i = 0; i < n; ++i) {
            for(int j = 0; j < n; ++j) {
                if ((mask & (1 << i)) == 0 && (mask & (1 << j)) > 0) {
                    res += a[j][i] * brute(mask ^ (1 << i));
                }
            }
        }
        res *= p;
        dm[mask] = res;
        fil[mask] = true;
        return dm[mask];
    }


