class Task {
    boolean get(int mask, int i){
        return (mask & (1 << i)) > 0;
    }

    int zero(int mask, int i){
        return mask & (~(1 << i));
    }

    public void solve() {
        int n = in.nextInt();
        double[][] a = new double[n][n];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++)
                a[i][j] = in.nextDouble();
        }
        double[] d = new double[1 << n];
        d[(1 << n) - 1] = 1;
        for (int mask = (1 << n) - 1; mask >= 0; mask--) {
            int bits = Integer.bitCount(mask);
            double transfer = 1.0 / (bits * (bits - 1) / 2);
            for (int i = 0; i < n; i++) {
                if (get(mask, i)) {
                    for (int j = i + 1; j < n; j++) {
                        if (get(mask, j)) {
                            d[zero(mask, j)] += a[i][j] * transfer * d[mask];
                            d[zero(mask, i)] += a[j][i] * transfer * d[mask];
                        }
                    }
                }
            }
        }
        for(int i = 0; i < n; i++)
            out.print(d[1 << i] + " ");
    }

    private InputReader in;
    private PrintWriter out;

    Task(InputReader in, PrintWriter out) {
        this.in = in;
        this.out = out;
    }
}

