public class Task16e {

	/**
	 * @param args
	 */
	public static void main(String[] args) {
		Scanner sc = new Scanner(System.in);
		int n = sc.nextInt();
		double[][] prob = new double[n][n];
		for (int i = 0; i < n; i++) {
			for (int j = 0; j < n; j++) {
				prob[i][j] = sc.nextDouble();
			}
		}
		double[] var = new double[1 << n];
		boolean[] was = new boolean[1 << n];
		Arrays.fill(var, 0.0);
		Arrays.fill(was, false);
		was[0] = true;
		var[(1 << n) - 1] = 1.0;
		Set<Integer> cr = new HashSet<Integer>();
		Set<Integer> nx = new HashSet<Integer>();
		nx.add((1 << n) - 1);
		boolean[] fish = new boolean[n];
		for (int cnt = 0; cnt < n -1; cnt++) {
			cr.clear();
			cr.addAll(nx);
			nx.clear();
			for (Iterator<Integer> iterator = cr.iterator(); iterator.hasNext();) {
				int curr = iterator.next();
				for (int i = 0; i < n; i++) {
					fish[i] = ((1 << i) & curr) != 0;
				}
				int fishn = 0;
				for (int i = 0; i < n; i++) {
					if (fish[i]) fishn++;
				}
				if (fishn == 1) continue;

				for (int i = 0; i < n; i++) {
					if (!fish[i]) continue;
					for (int j = i + 1; j < n; j++) {
						if (!fish[j]) continue;
						int woi = curr & ~(1 << i);
						int woj = curr & ~(1 << j);
						var[woi] += var[curr] * prob[j][i];
						var[woj] += var[curr] * prob[i][j];
						nx.add(woi);
						nx.add(woj);
					}
				}
			}
		}
		double sum = 0.0;
		for (int i = 0; i < n; i++) {
			sum += var[1 << i];
		}
		for (int i = 0; i < n; i++) {
			System.out.printf("%.6f ", var[1 << i] / sum);
		}
	}

}

import java.util.Scanner;

public class DarkAssembly {
	static int n, A;
	public static void main(String[] args) {
		Scanner sc = new Scanner(System.in);
		n = sc.nextInt();
		int k = sc.nextInt();
		A = sc.nextInt();

		int[][] sen = new int[n][2];
		for (int i = 0; i < n; i++) {
			sen[i][0] = sc.nextInt();
			sen[i][1] = sc.nextInt();
		}

		//Simple:
		sen = sort(sen);
		int tmp = k, cnt = 0;
		for (int i = 0; i < n; i++) {
			int canTake = (100-sen[i][1])/10;
			if (canTake <= tmp) {tmp-=canTake; cnt++;}
		}

		if (cnt > n/2) {System.out.println(1); return;}

		//Less simple
		System.out.println(distribute(0, k, sen));
	}

	private static double distribute(int id, int k, int[][] sen) {
		if (id < n) {//distribute
			double max = 0;			
			for (int i=0;i<=k;i++) {
					sen[id][1]+=10*i;
					max = Math.max(max, distribute(id+1, k-i,sen));
					sen[id][1]-=10*i;
			}

			return max;
		}
		else return compute(sen);

	}

	private static double compute(int[][] sen) {
		double rez = 0;

		int dist = 1<<n;
		for (int i = 0; i < dist; i++) {
			double p = 1;
			int B = 0, cnt = 0;
			for (int j = 0; j < n; j++) { 
				double sL = Math.min(sen[j][1]/100.0, 1);  
				if ((i & (1<<j)) == 1<<j) { //yes 
					p *= sL;
					cnt++;
				}
				else { //no
					B+=sen[j][0];
					p *= (1-sL);
				}
			}
			if (cnt <= n/2) p *= (double) A/(A+B);
			rez +=p;
		}
		return rez;
	}

	private static int[][] sort(int[][] sen) {
		for (int i = 0; i < n; i++) {
			int[] min = sen[i];
			int minI = i;
			for (int j = i+1; j < n; j++) {
				if (sen[j][1] > min[1]) {
					minI = j;
					min = sen[j];
				}
			}
			int[] tmp = sen[i];
			sen[i] = min;
			sen[minI] = tmp;
		}

		return sen;
	}
}

import java.util.Scanner;

public class DarkAssembly {
	static double ans = 0;
	static int n = 0 ;
	static double [] l;
	static int [] b;
	static double a;
	public static void main(String [] args){
		Scanner in = new Scanner(System.in);
		n = in.nextInt();
		int k = in.nextInt();
		a = in.nextInt();
		l = new double[n];
		b = new int[n];
		for(int i= 0 ; i < n ; i++){
			b[i]=in.nextInt();
			l[i]=in.nextInt()/100d;
		}
		make(0,k);
		System.out.println(ans);
	}
	public static void make(int i ,int k){
		if(k==0){
			ans = Math.max(prob(), ans);
			if(ans >= 1){
				System.out.println(1);
				System.exit(0);
			}
			return;
		}
		if(i==n){
			ans = Math.max(prob(), ans);
			if(ans >= 1){
				System.out.println(1);
				System.exit(0);
			}
			return;
		}
		int f = i;
		if(l[i]<0.95){
			l[i]+=0.1d;
			make(i,k-1);
			l[i]-=0.1d;
		}
		make(f+1,k);

	}
	public static double prob(){
		double ans = 0;
		for(int i = 0 ; i < (1<<n) ; i++){
			double B = 0 ;
			double t = 1;
			for(int j = 0 ; j < n; j++){
				if ( (i & ( 1 << j)) != 0){
					t*=l[j];
					if(t==0) 
						break;
				}
				else{
					t*=1-l[j];
					if(t==0) 
						break;
					B+=b[j];
				}
			}
			if(Integer.bitCount(i)*2 <= n){
				t*= a/(a+B);
			}
			ans+=t;

		}
		return ans;

	}

}

