/**
 * Built using CHelper plug-in
 * Actual solution is at the top
 *
 * @author Alex
 */
public class Main {
    public static void main(String[] args) {
        InputStream inputStream = System.in;
        OutputStream outputStream = System.out;
        InputReader in = new InputReader(inputStream);
        OutputWriter out = new OutputWriter(outputStream);
        TaskB solver = new TaskB();
        solver.solve(1, in, out);
        out.close();
    }
    static class TaskB {
        double special(int[] loyalties, int[] levels, int playerlevelsum) {
            int poss = 1 << loyalties.length;
            double res = 0;
            for(int pos = 0; pos < poss; pos++) {
                double occurs = 1;
                int happy = 0;
                int badlevelssum = 0;
                for(int i = 0; i < loyalties.length; i++) {
                    if(((pos >> i) & 1) == 1) { //happy senator
                        happy++;
                        occurs *= (double) loyalties[i] / 100;
                    } else { //unhappy senator
                        badlevelssum += levels[i];
                        occurs *= (double) (100 - loyalties[i]) / 100;
                    }
                }
                double winprob = (happy <= levels.length / 2) ? (double) playerlevelsum / (playerlevelsum + badlevelssum) : 1;
                res += occurs * winprob;
            }
            return res;
        }

        public void solve(int testNumber, InputReader in, OutputWriter out) {
            int senators = in.readInt(); // n, [1, 8]
            int sweets = in.readInt(); // k, [1, 8]
            int playerlevelsum = in.readInt(); // A, [1, 9999]
            int[] levels = new int[senators]; // [1, 9999]
            int[] loyalties = new int[senators]; // [0, 100] divisible by 10
            IOUtils.readIntArrays(in, levels, loyalties);
            ArrayList<ArrayList<Integer>> possibilities = new ArrayList<>(Arrays.asList(new ArrayList<>()));
            for(int senator = 0; senator < senators; senator++) {
                ArrayList<ArrayList<Integer>> newpossibilities = new ArrayList<>();
                for(ArrayList<Integer> al : possibilities) {
                    int sumsofar = 0;
                    for(int val : al) sumsofar += val;
                    int minadd = senator == senators - 1 ? sweets - sumsofar : 0;
                    for(int moar = minadd; moar <= sweets - sumsofar; moar++) {
                        ArrayList<Integer> copy = new ArrayList<>(al);
                        copy.add(moar);
                        newpossibilities.add(copy);
                    }
                }
                possibilities = newpossibilities;
            }
            double res = 0;
            for(ArrayList<Integer> al : possibilities) {
                int[] newloyalties = new int[senators];
                for(int i = 0; i < senators; i++) newloyalties[i] = Math.min(100, loyalties[i] + 10 * al.get(i));
                double special = special(newloyalties, levels, playerlevelsum);
                double tot = special;
                res = Math.max(res, tot);
            }
            out.printLine(res);
        }

    }

    static class InputReader {
        private InputStream stream;
        private byte[] buf = new byte[1024];
        private int curChar;
        private int numChars;
        private SpaceCharFilter filter;

        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        public int read() {
            if(numChars == -1)
                throw new InputMismatchException();
            if(curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf);
                } catch(IOException e) {
                    throw new InputMismatchException();
                }
                if(numChars <= 0)
                    return -1;
            }
            return buf[curChar++];
        }

        public int readInt() {
            int c = read();
            while(isSpaceChar(c))
                c = read();
            int sgn = 1;
            if(c == '-') {
                sgn = -1;
                c = read();
            }
            int res = 0;
            do {
                if(c < '0' || c > '9')
                    throw new InputMismatchException();
                res *= 10;
                res += c - '0';
                c = read();
            } while(!isSpaceChar(c));
            return res * sgn;
        }

        public boolean isSpaceChar(int c) {
            if(filter != null)
                return filter.isSpaceChar(c);
            return isWhitespace(c);
        }

        public static boolean isWhitespace(int c) {
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }

        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);

        }

    }

    static class OutputWriter {
        private final PrintWriter writer;

        public OutputWriter(OutputStream outputStream) {
            writer = new PrintWriter(new BufferedWriter(new OutputStreamWriter(outputStream)));
        }

        public OutputWriter(Writer writer) {
            this.writer = new PrintWriter(writer);
        }

        public void print(Object... objects) {
            for(int i = 0; i < objects.length; i++) {
                if(i != 0)
                    writer.print(' ');
                writer.print(objects[i]);
            }
        }

        public void printLine(Object... objects) {
            print(objects);
            writer.println();
        }

        public void close() {
            writer.close();
        }

    }

    static class IOUtils {
        public static void readIntArrays(InputReader in, int[]... arrays) {
            for(int i = 0; i < arrays[0].length; i++) {
                for(int j = 0; j < arrays.length; j++)
                    arrays[j][i] = in.readInt();
            }
        }

    }
}

import java.io.*;
import java.util.*;

public class B {

	int n, k;
	double A;
	int[] b, l;
	double ans;
	double curAns;

	void check(boolean[] used) {
		int cnt = 0;
		for (boolean t : used)
			if (t)
				cnt++;
		double prob = 1;
		for (int i = 0; i < n; i++) {
			if (used[i])
				prob *= ((double) l[i]) / ((double) 100);
			else
				prob *= 1 - ((double) l[i]) / ((double) 100);
		}
		if (2 * cnt > n) {
			curAns += prob;
		} else {
			int level = 0;
			for (int i = 0; i < n; i++)
				if (!used[i])
					level += b[i];
			curAns += prob * ( A / ((double) A + level));
		}
	}

	void go(int i, boolean[] used) {
		if (n == i) {
			check(used);
			return;
		}
		used[i] = true;
		go(i + 1, used);
		used[i] = false;
		go(i + 1, used);
	}

	void candies(int k, int i) {
		if (i == n) {
			curAns = 0;
			go(0, new boolean[n]);
			if (curAns > ans)
				ans = curAns;
			return;
		}
		candies(k, i + 1);
		for (int j = 1; j <= k && l[i] + 10 * j <= 100; j++) {
			l[i] += 10 * j;
			candies(k - j, i + 1);
			l[i] -= 10 * j;
		}
	}

	void solve() throws Exception {
		n = nextInt();
		k = nextInt();
		A = nextInt();
		b = new int[n];
		l = new int[n];
		for (int i = 0; i < n; i++) {
			b[i] = nextInt();
			l[i] = nextInt();		
		}
		ans = 0;
		candies(k, 0);
		out.printf("%.12f", ans);
	}

	void run() {
		try {
			in = new BufferedReader(new InputStreamReader(System.in));
			out = new PrintWriter(System.out);
			//			in = new BufferedReader(new FileReader(filename + ".in"));
			//			out = new PrintWriter(filename + ".out");
			Locale.setDefault(Locale.US);
			solve();

			out.close();
		} catch (Exception e) {
			e.printStackTrace();
			System.exit(1);
		}
	}

	BufferedReader in;
	StringTokenizer st;
	PrintWriter out;
	final String filename = new String("B").toLowerCase();

	String nextToken() throws Exception {
		while (st == null || !st.hasMoreTokens())
			st = new StringTokenizer(in.readLine());
		return st.nextToken();
	}

	int nextInt() throws Exception {
		return Integer.parseInt(nextToken());
	}

	long nextLong() throws Exception {
		return Long.parseLong(nextToken());
	}

	double nextDouble() throws Exception {
		return Double.parseDouble(nextToken());
	}

	public static void main(String[] args) {
		new B().run();
	}

}

import java.util.*;

public class B {

    static int[] loyality;
    static int[] level;
    static int mid;
    static int a, n;
    static double sol;

    public static void getMax(int idx, int rem) {
        if (idx == loyality.length) {
            double pos = 0;
            for (int i = 0; i < (1 << n); i++)
                pos += solve(i);
            sol = Math.max(sol, pos);
            return;
        }
        int cur = loyality[idx];
        int r = 0;
        while (r + cur <= 10 && r <= rem) {
            loyality[idx] = cur + r;
            getMax(idx + 1, rem - r);
            r++;
        }
        loyality[idx] = cur;
    }

    public static double solve(int mask) {
        int c = 0;
        int sum = 0;
        double b = 1;
        for (int i = 0; i < n; i++) {
            if (((1 << i) | mask) == mask) {
                c++;
                b *= (loyality[i] / 10.0);
            } else {
                sum += level[i];
                b *= (1 - (loyality[i] / 10.0));
            }
        }
        if (c >= mid)
            return b;
        return b * (a * 1.0) / (a + sum);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        n = sc.nextInt();
        int k = sc.nextInt();
        a = sc.nextInt();
        level = new int[n];
        loyality = new int[n];
        for (int i = 0; i < n; i++) {
            level[i] = sc.nextInt();
            loyality[i] = sc.nextInt() / 10;
        }
        mid = (n/2) +1;
        sol = 0;
        getMax(0, k);
        System.out.println(sol);
    }
}

