		int[] b = new int[n], l = new int[n];
		for (int i = 0; i < n; i++) {
			l[i] = iread();
			b[i] = iread();
		}

		int[] c = new int[n];
		double ans = 0.0;
		for (int mask = 0; mask < 1 << (k + n - 1); mask++) {
			int t = 0;
			for (int i = 0; i < n + k - 1; i++) {
				if ((mask & (1 << i)) != 0)
					t++;
			}
			if (t != k)
				continue;

			int x = mask;
			for (int i = 0; i < n; i++) {
				c[i] = b[i];
				while (x % 2 == 1) {
					c[i] += 10;
					x /= 2;
				}
				if (c[i] > 100)
					c[i] = 100;
				x /= 2;
			}
			double res = 0.0;
			for (int mask2 = 0; mask2 < 1 << n; mask2++) {
				int m = 0;
