public class flags1225 implements Runnable {
	static int n, k, a, b[], loy[];
	static boolean decision[];
	static double ans, max;

	static void check(int i) {
		if (i == n) {
			checkAgain();
			return;
		}
		decision[i] = true;
		check(i + 1);
		if (loy[i] < 100) {
			decision[i] = false;
			check(i + 1);
		}
	}

	static void checkAgain() {
		double prob = 1;
		int enemyEnergy = 0;
		int count = 0;
		for (int i = 0; i < n; i++) {
			if (decision[i]) {
				count++;
				prob *= loy[i];
			} else {
				prob = prob * (100 - loy[i]);
				enemyEnergy += b[i];
			}
		}
		double killProb = (double) (a) / (a + enemyEnergy);
		if (count > n / 2) {
			ans += prob;
			return;
		}
		prob *= killProb;
		ans += prob;
	}

	static void rec(int sum, int i) {
		if (i == n || sum == 0) {
			ans = 0;
			check(0);
			max = max(ans, max);
			return;
		}
		for (int j = 0; j <= sum; j = j + 10) {
			if (loy[i] + j > 100)
				continue;
			loy[i] += j;
			rec(sum - j, i + 1);
			loy[i] -= j;
		}
	}

	public void run() {
		n = nextInt();
		k = nextInt() * 10;
		a = nextInt();
		max = 0;
		b = new int[n];
		loy = new int[n];
		decision = new boolean[n];
