			b[i] = nextInt();
			loy[i] = nextInt();
		}
		// System.out.println(Arrays.toString(loy));
		rec(k, 0);
		long pow = (long) pow(100, n);
		out.print((double) max / pow);

		// --------------------------------------------------------------------------------------------
		out.close();
		System.exit(0);
	}

