               lvlcnt += lvl[j];

            if ((p == 0)&&(votesGood))
               passed = false;
            if ((p == 100)&&(!votesGood))
               passed = false;
            if (!passed)
               break;

            if (votesGood)
               pt *= (p/100.0);
            else
               pt *= ((100-p)/100.0);
         }

         if (passed == false)
            continue;

         if (2*nG <= N)
         {
            // Calculate if we kill all senators
            double p1 = A/(1.0*(A+lvlcnt));

            // Add in the probability of losing
            res += (1-p1)*pt;
         }
      }

      return 1.0-res;
   }

   HashMap<Integer, Double> memo;
   double go(int i, int[] cc)
   {
      if (i == -1)
         return calc(i, cc);

      int hv = hash(i, cc);
      Double rr = memo.get(hv);
      if (rr != null)
         return rr;

      double res = go(i-1, cc);
      for (int j=0; j<N; j++)
      {
         int cv = vs[j]+cc[j]*10;
         if (cv == 100)
            continue;

         cc[j]++;
         double rrr = go(i-1, cc);
         cc[j]--;

         if (rrr > res)
            res = rrr;
      }

      memo.put(hv, res);
      return res;
   }

   public B(FastScanner in)
   {
      N = in.nextInt();
      K = in.nextInt();
      A = in.nextInt();
      memo = new HashMap<Integer, Double>();

      lvl = new int[N];
      vs = new int[N];
      for (int i=0; i<N; i++)
      {
         lvl[i] = in.nextInt();
         vs[i] = in.nextInt();
      }

      int[] cs = new int[8];
      double res = go(K-1, cs);
      System.out.printf("%.10f%n", res);
   }
}


