class TaskB {

    static int myLevel;
    static int[] level;
    static int[] loyalty;

    static double get(int n) {
        double ret = 0;
        for (int mask = 0; mask < 1 << n; mask++) {
            int k = Integer.bitCount(mask);
            double prob = 1.;
            int sum = 0;
            for (int i = 0; i < n; i++) {
                if (((mask >> i) & 1) == 1) {
                    prob *= loyalty[i] * .1;
                } else {
                    prob *= (10 - loyalty[i]) * .1;
                    sum += level[i];
                }
            }
            if (k * 2 > n) {
                ret += prob;
            } else {
                ret += prob * myLevel / (myLevel + sum);
            }
        }
        return ret;
    }

    static double go(int x, int k, int n) {
        if (x == n) {
            return get(n);
        }
        double ret = 0;
        for (int i = 0; i <= k && loyalty[x] + i <= 10; i++) {
            loyalty[x] += i;
            ret = Math.max(go(x + 1, k - i, n), ret);
            loyalty[x] -= i;
        }
        return ret;
    }

    public void solve(int testNumber, FastScanner in, FastPrinter out) {
        int n = in.nextInt();
        int k = in.nextInt();
        myLevel = in.nextInt();
        level = new int[n];
