	public int nextPerm(int[] a, int k) {
		if (a[0] == k)
			return -1;
		int last = 0;
		for (int i = a.length - 1; i >= 0; i--)
			if (a[i] != 0) {
				last = i;
				break;
			}
		int mem=a[last];
		a[last-1]++;
		a[last]=0;
		a[a.length-1]=mem-1;
		return 0;
	}

	public double poss(int A,int[][] sen,int[] rasp){
		int n=sen.length;
		double[] possluck=new double[n];
		for(int i=0;i<n;i++)
			possluck[i]=Math.min(100, sen[i][1]+rasp[i]*10)/100.0;
		double poss=0;
		for(int i=0;i<(1<<n);i++){
			int kol=0;
			for(int j=0;j<n;j++)
				if((i%(1<<(j+1)))/(1<<(j))==1)
					kol++;
			double thisposs=1;
			for(int j=0;j<n;j++)
				if((i%(1<<(j+1)))/(1<<(j))==1)
					thisposs*=possluck[j];
				else
					thisposs*=(1-possluck[j]);
			if(kol>n/2)
				poss+=thisposs;
			else{
				double lvl=0;
				for(int j=0;j<n;j++)
					if((i%(1<<(j+1)))/(1<<(j))==0)
						lvl+=sen[j][0];
				poss+=thisposs*(A/(A+lvl));
			}
		}
		return poss;
	}

