                    } else
                    {
                        P*=1.0-a[i].l/100.;
                        q+=a[i].b;
                    }
                }
                if (Integer.bitCount(mask)>n/2)
                {
                    tmp+=P;
                } else
                {
                    tmp+=P*A/(A+q);
                }
                max=Math.max(tmp,max);
            }
