            for(int i=0;i<n;i++)
            {
                b[i] = a[i].l;
                while(x%2==1)
                {
                    b[i]+=10;
                    x/=2;
                }
                b[i]=Math.min(b[i],100);
                x/=2;
            }
            double tmp=0;
            for(int w=0; w<(1<<n);w++)
            {
                double p = 1.;
                double B = 0;
                for(int i = 0; i < n; i++)
                    if((w >> i & 1) != 0) p *= b[i] / 100.;
                    else
