            l[i] = in.nextInt();
        }
        out.println( best( 0, k ));
    }

    double best( int cur, int left ) {
        double r = 0.0;
        if ( cur < l.length ) {
            for ( int i = 0; i <= left && l[cur] + 10 * i <= 100; i ++ ) {
                l[cur] += i * 10;
                r = Math.max( r, best( cur + 1, left - i ) );
                l[cur] -= i * 10;
            }
        } else {
            for ( int m = 0; m < ( 1 << l.length ); m ++ ) {
                int sum = 0;
                double p = 1.0;
                int pro = 0;
                for ( int i = 0; i < l.length; i ++ ) {
                    if ( ( m & ( 1 << i ) ) == 0 ) {
                        p *= 1.0 - l[i] * 0.01;
                        sum += b[i];
                    } else {
                        p *= l[i] * 0.01;
                        pro ++;
                    }
                }
                if ( pro * 2 > l.length ) {
                    r += p;
                } else {
                    r += ( p * a ) / ( a + sum );
                }
            }
        }
        return r;
