	double ans;
	int[] sw;
	int a;

	void sol() {
		for (int i = 0; i < n; i++) l[i] += sw[i] * 10;
		double yes = 0;
		for (int q = 0; q < (1 << n); q++) {
			double p = 1;
			int bb = 0;
			int cnt = 0;
			for (int i = 0; i < n; i++) {
				if ((q & (1 << i)) == 0) {
					p *= (1.0 - (double)l[i] / 100);
					bb += b[i];
				} else {
					p *= 1.0 * (double)l[i] / 100;
					cnt++;
				}
			}
			if (cnt > n / 2) {
				yes += p;
			} else {
				yes += p * (double)a / (double)(a + bb); 
			}
		}
		if (ans < yes) ans = yes;
		for (int i = 0; i < n; i++) l[i] -= sw[i] * 10;
	}

	void rek(int i, int k) {
		if (i == n) sol(); else {
			for (int q = 0; q <= k && l[i] + q * 10 <= 100; q++) {
				sw[i] = q;
				rek(i + 1, k - q);
			}
		}
	}

