                        B += ss[i].level;
                    }
                }
                if(app > half)sum += p;
                else{
                    sum += p * A / (A+B);
                }
            }
            ans = max(ans, sum);
            return;
        }
        for(int i = 0; i <= rest; i++){
            int old = ss[pos].loyal;
            int nl = ss[pos].loyal + i * 10;
            if(nl > 100)break;
            ss[pos].loyal = nl;
            tra(ss, pos+1, rest-i);
            ss[pos].loyal = old;
        }
    }
}

class S implements Comparable<S>{
    int level, loyal;
    S(int a, int b){
        level = a;
        loyal = b;
    }
    public int compareTo(S s){
        return this.loyal - s.loyal;
    }
}

