        int p[] = new int[s.length() + 1];
        int n = s.length();
        p[0] = 0;
        for (int i = 2; i <= n; i++) {
            p[i] = p[i - 1];
            while (p[i] > 0 && s.charAt(p[i]) != s.charAt(i - 1)) p[i] = p[p[i]];
            if (s.charAt(p[i]) == s.charAt(i - 1)) p[i]++;
        }
        return p;
