    {
        if (n == 0)
            return 1;
        if (n % 2 == 1)
            return binpow (a % MOD, (n-1) % MOD ) * a % MOD;
        else {
            long b = binpow(a % MOD, n/2 % MOD) % MOD;
            return (b * b) % MOD;
        }
    }

