public class D {
	static int dp(int i,int start,int msk)
	{
		if(Integer.bitCount(msk)==n)
			return s_e[i][start];

		if(dp[i][start][msk]!=-1)
			return dp[i][start][msk];

		int max=0;
		for(int k=0;k<n;k++)
		{	
			int min=Integer.MAX_VALUE;
			if((msk & (1<<k)) == 0 )
			{
				min=diff[i][k];
				min=Math.min(min, dp(k,start,msk | (1<<k)));
				max=Math.max(max, min);
			}
		}
		return dp[i][start][msk]=max;
	}
