        }
        pre = new int[n][n];
        pre_stop_and_start = new int[n][n];
        for(int i=0;i<n;++i) {
            for(int j=i+1;j<n;++j) {
                int min = Integer.MAX_VALUE;
                for(int k=0;k<m;++k) {
                    min = min(min, abs(mat[i][k] - mat[j][k]));
                }
                pre[i][j] = pre[j][i] = min;
            }
        }
        for(int i=0;i<n;++i) {
            for(int j=0;j<n;++j) {
                if(j==i) {
                    continue;
                }
                int min = Integer.MAX_VALUE;
                for(int k=0;k+1<m;++k) {
                    min = min(min, abs(mat[j][k+1] - mat[i][k]));
                }
                pre_stop_and_start[i][j] = min;
            }
        }
