    public static class Task implements Runnable {
        final FastIO io;
        final Debug debug;
        int inf = (int) 1e9 + 2;
        BitOperator bitOperator = new BitOperator();
        Modular modular = new Modular((int) 1e9 + 7);

        public Task(FastIO io, Debug debug) {
            this.io = io;
            this.debug = debug;
        }

        @Override
        public void run() {
            solve();
        }

        int[][][] f;
        int n;
        int t;
        int[] songTimes;
        int[] songTypes;
        int mask;

        public void solve() {
            n = io.readInt();
            t = io.readInt();
            mask = 1 << n;
            f = new int[4][mask][t + 1];
            for (int i = 0; i < 4; i++) {
                for (int j = 0; j < mask; j++) {
                    for (int k = 0; k <= t; k++) {
                        f[i][j][k] = -1;
                    }
                }
            }

            songTimes = new int[n + 1];
            songTypes = new int[n + 1];
            for (int i = 1; i <= n; i++) {
                songTimes[i] = io.readInt();
                songTypes[i] = io.readInt();
            }

            int ans = 0;
            for (int i = 0; i < 4; i++) {
                for (int j = 0; j < mask; j++) {
                    ans = modular.plus(ans, f(i, j, t));
                }
            }

            io.cache.append(ans);
        }

        int f(int i, int j, int k) {
            if (j == 0) {
                return k == 0 && i == 0 ? 1 : 0;
            }
            if (k < 0) {
                return 0;
            }
            if (f[i][j][k] == -1) {
                f[i][j][k] = 0;
                for (int x = 1; x <= n; x++) {
                    if (songTypes[x] != i || bitOperator.bitAt(j, x - 1) == 0) {
                        continue;
                    }
                    for (int y = 0; y < 4; y++) {
                        if (y == i) {
                            continue;
                        }
                        f[i][j][k] = modular.plus(f[i][j][k], f(y, bitOperator.setBit(j, x - 1, false), k - songTimes[x]));
                    }
                }
            }
            return f[i][j][k];
        }
    }

    /**
     * 模运算
     */
    public static class Modular {
        int m;

        public Modular(int m) {
            this.m = m;
        }

        public int valueOf(int x) {
            x %= m;
            if (x < 0) {
                x += m;
            }
            return x;
        }

        public int valueOf(long x) {
            x %= m;
            if (x < 0) {
                x += m;
            }
            return (int) x;
        }

        public int mul(int x, int y) {
            return valueOf((long) x * y);
        }

        public int plus(int x, int y) {
            return valueOf(x + y);
        }

        @Override
        public String toString() {
            return "mod " + m;
        }
    }

    public static class BitOperator {
        public int bitAt(int x, int i) {
            return (x >> i) & 1;
        }

        public int bitAt(long x, int i) {
            return (int) ((x >> i) & 1);
        }

        public int setBit(int x, int i, boolean v) {
            if (v) {
                x |= 1 << i;
            } else {
                x &= ~(1 << i);
            }
            return x;
        }

        public long setBit(long x, int i, boolean v) {
            if (v) {
                x |= 1L << i;
            } else {
                x &= ~(1L << i);
            }
            return x;
        }

        /**
         * Determine whether x is subset of y
         */
        public boolean subset(long x, long y) {
            return intersect(x, y) == x;
        }

        /**
         * Merge two set
         */
        public long merge(long x, long y) {
            return x | y;
        }

        public long intersect(long x, long y) {
            return x & y;
        }

        public long differ(long x, long y) {
            return x - intersect(x, y);
        }
    }

