                                                    dp[i + 1][2][j][k][l - 1] %= mod;
                                                    go[i + 1][2][j][k][l - 1] = true;
                                                }
                                            } else {
                                                if (j > 0) {
                                                    dp[i + 1][0][j - 1][k][l] += dp[i][m][j][k][l] * j;
                                                    dp[i + 1][0][j - 1][k][l] %= mod;
                                                    go[i + 1][0][j - 1][k][l] = true;
