public class Main
{
	static final int MOD = (int)1e9 + 7;
	static int n;
	static int[] t;
	static int[] g;	
	static int[][] memo;

	static int dp(int mask, int rem, int last)
	{
		if(rem == 0)
			return 1;
		if(memo[last][mask] != -1)
			return memo[last][mask];

		int ans = 0;
		for(int i = 0; i < n; i++)
		{
			if((mask & (1 << i)) == 0 && rem >= t[i] && g[i] != last)
				ans += dp(mask | 1 << i, rem - t[i], g[i]);

			if(ans >= MOD)
				ans -= MOD;
		}

		return memo[last][mask] = ans;
	}

