        for (int i =0;i<n;i++){
            if ((msk&1<<i)==0){
                if (gen[i]!=last&&val[i]<=rem){
                    ans+=dp(gen[i],rem-val[i],msk|1<<i);
                    ans%=mod;
                }
            }
        }
        return memo[last][rem][msk]=ans;
    }
