				for (int mask1 = 0; mask1 < 1 << n; mask1++) {
					int cdyn = dynNext[mask1];
					for (int mask2 = mask1;; mask2 = (mask2 - 1) & mask1) {
						cdyn = max(cdyn, dyn[mask2] + sums[mask1 ^ mask2]);
						if (mask2 == 0) {
