public class Main {
    public static void main(String[] args) {
        InputStream inputStream = System.in;
        OutputStream outputStream = System.out;
        Input in = new Input(inputStream);
        PrintWriter out = new PrintWriter(outputStream);
        TaskE solver = new TaskE();
        solver.solve(1, in, out);
        out.close();
    }

    static class TaskE {
        public void solve(int testNumber, Input in, PrintWriter out) {
            try {
                int kt = in.readInt();
                for (int nt = 0; nt < kt; nt++) {
                    int n = in.readInt();
                    int m = in.readInt();
                    int[][] a = new int[m][n];
                    for (int i = 0; i < n; i++) {
                        for (int j = 0; j < m; j++) {
                            a[j][i] = in.readInt();
                        }
                    }

                    Arrays.sort(a, (x, y) -> {
                        int xMax = 0;
                        for (int i = 0; i < x.length; i++) {
                            xMax = Math.max(xMax, x[i]);
                        }
                        int yMax = 0;
                        for (int i = 0; i < y.length; i++) {
                            yMax = Math.max(yMax, y[i]);
                        }
                        return Integer.compare(-xMax, -yMax);
                    });

                    int ans = 0;
                    int[] s = new int[4];
                    for (s[0] = 0; s[0] < n; s[0]++) {
                        for (s[1] = 0; s[1] < n; s[1]++) {
                            for (s[2] = 0; s[2] < n; s[2]++) {
                                for (s[3] = 0; s[3] < n; s[3]++) {
                                    int cur = 0;
                                    for (int i = 0; i < n; i++) {
                                        int max = 0;
                                        for (int j = 0; j < Math.min(m, n); j++) {
                                            max = Math.max(max, a[j][(i + s[j]) % n]);
                                        }
                                        cur += max;
                                    }
                                    ans = Math.max(cur, ans);
                                }
                            }
                        }
                    }

                    out.println(ans);
                }

            } catch (Exception e) {
                throw new RuntimeException(e);
            }
        }

    }

    static class Input {
        public final BufferedReader reader;
        private String line = "";
        private int pos = 0;

        public Input(InputStream inputStream) {
            reader = new BufferedReader(new InputStreamReader(inputStream));
        }

        private boolean isSpace(char ch) {
            return ch <= 32;
        }

        public String readWord() throws IOException {
            skip();
            int start = pos;
            while (pos < line.length() && !isSpace(line.charAt(pos))) {
                pos++;
            }
            return line.substring(start, pos);
        }

        public int readInt() throws IOException {
            return Integer.parseInt(readWord());
        }

        private void skip() throws IOException {
            while (true) {
                if (pos >= line.length()) {
                    line = reader.readLine();
                    pos = 0;
                }
                while (pos < line.length() && isSpace(line.charAt(pos))) {
                    pos++;
                }
                if (pos < line.length()) {
                    return;
                }
            }
        }

    }
}

import java.io.*;
import java.util.*;

public class E
{
    PrintWriter out = new PrintWriter(new BufferedWriter(new OutputStreamWriter(System.out)));
    BufferedReader in = new BufferedReader(new InputStreamReader(System.in));
    StringTokenizer tok;

    public void go() throws IOException
    {
        StringTokenizer tok = new StringTokenizer(in.readLine());
        int zzz = Integer.parseInt(tok.nextToken());
        for (int zz = 0; zz < zzz; zz++)
        {
            ntok();
            int n = ipar();
            int m = ipar();
            int[][] mat = new int[n][m];
            for (int i = 0; i < n; i++)
            {
                ntok();
                mat[i] = iapar(m);
            }
            long[][] dp = new long[1 << n][m+1];
            for (int i = 0; i < 1 << n; i++)
            {
                dp[i][m] = -1000000000;
            }
            dp[(1 << n) - 1][m] = 0;
            for (int i = m-1; i >= 0; i--)
            {
                for (int e = 0; e < 1 << n; e++)
                {
                    dp[e][i] = dp[e][i+1];
                    for (int w = 0; w < 1 << n; w++)
                    {
                        if ((e & w) == 0)
                        {
                            dp[e][i] = Math.max(dp[e][i], best(w, mat, i) + dp[e|w][i+1]);
                        }
                    }
                }
            }
            // for (long[] arr : dp)
            // {
            //     out.println(Arrays.toString(arr));
            // }
            out.println(dp[0][0]);
        }

        out.flush();
        in.close();
    }

    public long best(int mask, int[][] mat, int col)
    {
        long max = 0;
        for (int t = 0; t < mat.length; t++)
        {
            long sum = 0;
            int mk = mask;
            for (int i = 0; i < mat.length; i++)
            {
                if (mk % 2 == 1)
                {
                    sum += mat[i][col];
                }
                mk /= 2;
            }
            max = Math.max(max, sum);
            cycle(mat, col);
        }
        return max;
    }

    public void cycle(int[][] mat, int col)
    {
        int temp = mat[0][col];
        for (int i = 0; i < mat.length-1; i++)
        {
            mat[i][col] = mat[i+1][col];
        }
        mat[mat.length-1][col] = temp;
    }

    public void ntok() throws IOException
    {
        tok = new StringTokenizer(in.readLine());
    }

    public int ipar()
    {
        return Integer.parseInt(tok.nextToken());
    }

    public int[] iapar(int n)
    {
        int[] arr = new int[n];
        for (int i = 0; i < n; i++)
        {
            arr[i] = ipar();
        }
        return arr;
    }

    public long lpar()
    {
        return Long.parseLong(tok.nextToken());
    }

    public long[] lapar(int n)
    {
        long[] arr = new long[n];
        for (int i = 0; i < n; i++)
        {
            arr[i] = lpar();
        }
        return arr;
    }

    public double dpar()
    {
        return Double.parseDouble(tok.nextToken());
    }

    public String spar()
    {
        return tok.nextToken();
    }

    public static void main(String[] args) throws IOException
    {
        new E().go();
    }
}

