public class E implements Runnable {
	FastReader scn;
	PrintWriter out;
	String INPUT = "";

	void solve() {
		int t = scn.nextInt();
		while(t-- > 0) {
			int n = scn.nextInt(), m = scn.nextInt();
			int[][] arr = scn.next2DInt(n, m);

			int[][] col = new int[m][2];
			for(int j = 0; j < m; j++) {
				int max = 0;
				for(int i = 0; i < n; i++) {
					max = Math.max(max, arr[i][j]);
				}
				col[j][0] = max;
				col[j][1] = j;
			}
			Arrays.parallelSort(col, (o1, o2) -> o2[0] - o1[0]);

			m = Math.min(n, m);

			int[][] lol = new int[n][m];

			for(int j = 0; j < m; j++) {
				for(int i = 0; i < n; i++) {
					lol[i][j] = arr[i][col[j][1]];
				}
			}

			int[] row = new int[n];
			for(int i = 0; i < n; i++) {
				row[i] = lol[i][0];
			}

			ans = 0;
			func(lol, 1, row);
			out.println(ans);
		}
	}

	int ans;

	void func(int[][] arr, int col, int[] rowM) {
		int n = arr.length, m = arr[0].length;
		if(col >= m) {
			int rv = 0;
			for(int a : rowM) {
				rv += a;
			}
			ans = Math.max(ans, rv);
			return;
		}

		int max = 0, ind = -1;
		for(int i = 0; i < n; i++) {
			if(arr[i][col] > max) {
				max = arr[i][col];
				ind = i;
			}
		}

		boolean in = false;
		for(int r = 0; r < n; r++) {
			if(max <= rowM[r]) {
				continue;
			}
			int rot = (ind - r + n) % n;
			int[] need = new int[n], copy = Arrays.copyOf(rowM, n);
			for(int i = 0; i < n; i++) {
				need[i] = arr[(i + rot) % n][col];
			}
			for(int i = 0; i < n; i++) {
				arr[i][col] = need[i];
				copy[i] = Math.max(rowM[i], arr[i][col]);
			}

			ind = r;
			in = true;
			func(arr, col + 1, copy);
		}

		if(!in) {
			func(arr, col + 2, rowM);
		}
	}

