                            }
                        }
                        cur[j] = Math.max(cur[j], sum);
                    }
                }
                for (int j = 0; j < (1 << n); j++) {
                    for (int k = j; ; k = (k - 1) & j) {
                        dp[i & 1][j] = Math.max(dp[i & 1][j], dp[(i - 1) & 1][k] + cur[j ^ k]);
