			for(int i = 1;i < 1<<n;i+=2){
				int[] ss = new int[m];
				for(int j = 0;j < m;j++){
					int cur = i;
					int lmax = 0;
					for(int sh = 0;sh < n;sh++){
						int s = 0;
						for(int k = 0;k < n;k++){
							if(cur<<~k<0){
								s += a[k][j];
							}
						}
						lmax = Math.max(lmax, s);
						cur = cur>>>1|(cur&1)<<n-1;
					}
					ss[j] = lmax;
				}
				sss[i] = ss;
			}
			ptns = new HashMap<>();
