				h= h * 1000000009 + v;
			}
//			all.add(h);
			ptns.put(h, ptn);
			return;
		}

		for(int i = 0;i <= max+1;i++){
			a[pos] = i;
			dfs(a, pos+1, Math.max(i, max));
		}
	}

	void run() throws Exception
	{
