/**
 * Built using CHelper plug-in
 * Actual solution is at the top
 */
public class Main {
    public static void main(String[] args) {
        InputStream inputStream = System.in;
        OutputStream outputStream = System.out;
        Scanner in = new Scanner(inputStream);
        PrintWriter out = new PrintWriter(outputStream);
        E1RotateColumnsEasyVersion solver = new E1RotateColumnsEasyVersion();
        solver.solve(1, in, out);
        out.close();
    }

    static class E1RotateColumnsEasyVersion {
        int n;
        int m;
        int[][] arr;
        int[][][] mskValue;
        int[][] memo;

        public void solve(int testNumber, Scanner sc, PrintWriter pw) {
            int q = sc.nextInt();
            while (q-- > 0) {
                n = sc.nextInt();
                m = sc.nextInt();
                arr = new int[n][m];
                for (int i = 0; i < n; i++)
                    for (int j = 0; j < m; j++)
                        arr[i][j] = sc.nextInt();
                mskValue = new int[n][1 << n][m];
                for (int i = 0; i < m; i++)
                    for (int shift = 0; shift < n; shift++)
                        for (int msk = 0; msk < 1 << n; msk++)
                            for (int j = 0; j < n; j++)
                                if ((msk & 1 << j) != 0)
                                    mskValue[shift][msk][i] += arr[(j + shift) % n][i];
                memo = new int[1 << n][m];
                for (int[] x : memo)
                    Arrays.fill(x, -1);
                pw.println(dp(0, 0));
            }
        }

        private int dp(int idx, int msk) {
            if (msk == (1 << n) - 1)
                return 0;
            if (idx == m)
                return (int) -1e9;
            int max = Integer.MIN_VALUE;
            if (memo[msk][idx] != -1)
                return memo[msk][idx];
            for (int shift = 0; shift < n; shift++) {
                for (int i = 0; i < 1 << n; i++)
                    if ((msk & i) == 0)
                        max = Math.max(max, mskValue[shift][i][idx] + dp(idx + 1, msk | i));
            }
            return memo[msk][idx] = max;
        }

    }

    static class Scanner {
        StringTokenizer st;
        BufferedReader br;

        public Scanner(FileReader r) {
            br = new BufferedReader(r);
        }

        public Scanner(InputStream s) {
            br = new BufferedReader(new InputStreamReader(s));
        }

        public String next() {
            while (st == null || !st.hasMoreTokens()) {
                try {
                    st = new StringTokenizer(br.readLine());
                } catch (IOException e) {
                    throw new RuntimeException(e);
                }
            }
            return st.nextToken();
        }

        public int nextInt() {
            return Integer.parseInt(next());
        }

    }
}

