  void solve() {
    int T = nextInt();
//    int T = 1;
    for (int i = 0; i < T; i++) {
      helper();
    }
  }

  void helper() {
    int n = nextInt();
    int m = nextInt();
    int[][] mat = new int[n][m];
    List<Integer> all = new ArrayList<>();
    for (int i = 0; i < n; i++) {
      mat[i] = nextIntArr(m);
      for (int v : mat[i]) {
        all.add(v);
      }
    }
    Collections.sort(all);
    Collections.reverse(all);
    if (n < 4) {
      int res = 0;
      for (int i = 0; i < n; i++) {
        res += all.get(i);
      }
      outln(res);
      return;
    }
    int res = 0;
    int[] maxCol = new int[m];
    for (int j = 0; j < m; j++) {
      int tmp = 0;
      for (int i = 0; i < n; i++) {
        tmp = Math.max(tmp, mat[i][j]);
      }
      maxCol[j] = tmp;
    }
    for (int j1 = 0; j1 < m; j1++) {
      List<Integer> col = new ArrayList<>();
      for (int i = 0; i < n; i++) {
        col.add(mat[i][j1]);
      }
      Collections.sort(col);
      Collections.reverse(col);

      List<Integer> others = new ArrayList<>();
      for (int j2 = 0; j2 < m; j2++) {
        if (j2 != j1) {
          others.add(maxCol[j2]);
        }
      }

      Collections.sort(others);
      Collections.reverse(others);

      // Take one from col, three from others
      if (others.size() >= 3) {
        int tmp = col.get(0);
        for (int i = 0; i < 3; i++) {
          tmp+= others.get(i);
        }
        res = Math.max(res, tmp);
      }
      // Take two from col, two from others
      if (others.size() >= 2) {
        int tmp = col.get(0) + col.get(1);
        tmp += others.get(0) + others.get(1);
        res = Math.max(res, tmp);
      }
      // Take three from col, one from others
      if (others.size() >= 1) {
        int tmp = col.get(0) + col.get(1) + col.get(2);
        tmp += others.get(0);
        res = Math.max(res, tmp);
      }
      // Take all from col
      res = Math.max(res, col.get(0) + col.get(1) + col.get(2) + col.get(3));
    }

    for (int j1 = 0; j1 < m; j1++) {
      for (int j2 = 0; j2 < m; j2++) {
        if (j2 != j1) {
          for (int i1 = 0; i1 <= 3; i1++) {
            for (int i = 0; i <= 3; i++) {
              int tmp = mat[i1][j1] + mat[(i1 + 1) % 4][j1];
              tmp += mat[i][j2] + mat[(i + 1) % 4][j2];
              res = Math.max(res, tmp);
            }
          }

          int m1 = mat[0][j1] + mat[2][j1];
          m1 = Math.max(m1, mat[1][j1] + mat[3][j1]);
          int m2 = mat[0][j2] + mat[2][j2];
          m2 = Math.max(m2, mat[1][j2] + mat[3][j2]);
          res = Math.max(res, m1 + m2);
        }
      }
    }

    outln(res);
  }

  void shuffle(long[] a) {
    int n = a.length;
    for(int i = 0; i < n; i++) {
      int r = i + (int) (Math.random() * (n - i));
      long tmp = a[i];
      a[i] = a[r];
      a[r] = tmp;
    }
  }

  int gcd(int a, int b) {
    while(a != 0 && b != 0) {
      int c = b;
      b = a % b;
      a = c;
    }
    return a + b;
  }
