    static class TaskE2 {
        public void solve(int testNumber, FastScanner in, PrintWriter out) {
            int t = in.nextInt();
            while (t-- > 0) {
                int n = in.nextInt(), m = in.nextInt();
                int[][] a = new int[n][m];
                for (int i = 0; i < n; i++) {
                    for (int j = 0; j < m; j++) {
                        a[i][j] = in.nextInt();
                    }
                }
                boolean[][] interesting = new boolean[n][m];
                boolean[] hasInteresting = new boolean[m];
                for (int i = 0; i < n; i++) {
                    List<Pair> list = new ArrayList<>();
                    for (int j = 0; j < m; j++) {
                        list.add(new Pair(a[i][j], j));
                    }
                    Collections.sort(list, Comparator.comparing(pair -> -pair.val));
                    for (int j = 0; j < m && j <= n; j++) {
                        interesting[i][list.get(j).pos] = true;
                        hasInteresting[list.get(j).pos] = true;
                    }
                }
                boolean[] goodMask = new boolean[1 << n];
                for (int mask = 0; mask < 1 << n; mask++) {
                    int best = Integer.MAX_VALUE;
                    int cur = mask;
                    do {
                        best = Math.min(best, cur);
                        cur = (cur >> 1) | ((cur & 1) << (n - 1));
                    } while (cur != mask);
                    goodMask[mask] = (mask == best);
                }
                int[] dp = new int[1 << n];
                for (int i = 0; i < m; i++) {
                    if (!hasInteresting[i]) {
                        continue;
                    }
                    for (int j = 0; j < n; j++) {
                        if (!interesting[j][i]) {
                            continue;
                        }
                        int supermask = (1 << n) - 1 - (1 << j);
                        int val = a[j][i];
                        for (int mask = supermask; ; mask = (mask - 1) & supermask) {
                            if (dp[mask] + val > dp[mask | (1 << j)]) {
                                dp[mask | (1 << j)] = dp[mask] + val;
                            }
                            if (mask == 0) {
                                break;
                            }
                        }
                    }
                    for (int mask = 0; mask < 1 << n; mask++) {
                        if (!goodMask[mask]) {
                            continue;
                        }
                        int best = 0;
                        int cur = mask;
                        do {
                            best = Math.max(best, dp[cur]);
                            cur = (cur >> 1) | ((cur & 1) << (n - 1));
                        } while (cur != mask);
                        do {
                            dp[cur] = best;
                            cur = (cur >> 1) | ((cur & 1) << (n - 1));
                        } while (cur != mask);
                    }
                }
                out.println(dp[(1 << n) - 1]);
            }
        }

        class Pair {
            int val;
            int pos;

            public Pair(int val, int pos) {
                this.val = val;
                this.pos = pos;
            }

        }

    }

    static class FastScanner {
        BufferedReader br;
        StringTokenizer st;

        public FastScanner(InputStream in) {
