                    sg2.setSet(mask);
                    while (sg2.hasNext()) {
                        profits[i][sg2.next] = Math.max(profits[i][sg2.next], sg2.val);
                        sg2.next();
                    }
                }
            }

            prefix[0] = profits[0];
            for (int i = 1; i < cols.length; i++) {
                for (int j = 0; j <= mask; j++) {
                    sg.setSet(j);
                    prefix[i][j] = prefix[i - 1][j];
                    while (sg.hasNext()) {
                        int next = sg.next();
                        prefix[i][j] = Math.max(prefix[i][j],
                                profits[i][next] + prefix[i - 1][j ^ next]);
                    }
                }
            }

