	//Main
	void main() {

		int n=inp.nextInt();
		m=inp.nextInt();
		String s=inp.next();
		dp=new int[1<<m];
		Arrays.fill(dp, -1);
		freq=new int[m][m];
		for(int i=0;i<n-1;i++) {
			int x=s.charAt(i)-'a';
			int y=s.charAt(i+1)-'a';
			if(x==y) continue;
			freq[x][y]++;
			freq[y][x]++;
		}
		out.println(go(0,0));

	}

	int go(int pos, int mask) {
		if(pos==m) return 0;
		if(dp[mask]!=-1) return dp[mask];
		int gg=Integer.MAX_VALUE;
		for(int i=0;i<m;i++) {
			if((mask>>i&1)==1) continue;
			int cost=0;
			for(int j=0;j<m;j++) {
				if((mask>>j&1)==1) cost+=freq[i][j]*pos;
				else cost-=freq[i][j]*pos;
			}
			cost+=go(pos+1,mask|(1<<i));
			gg=Math.min(gg, cost);
		}
		return dp[mask]=gg;
	}




