import java.io.*;
import java.util.*;

public class Main {

    static class Reader
    {
        final private int BUFFER_SIZE = 1 << 16;
        private DataInputStream din;
        private byte[] buffer;
        private int bufferPointer, bytesRead;

        public Reader()
        {
            din = new DataInputStream(System.in);
            buffer = new byte[BUFFER_SIZE];
            bufferPointer = bytesRead = 0;
        }

        public Reader(String file_name) throws IOException
        {
            din = new DataInputStream(new FileInputStream(file_name));
            buffer = new byte[BUFFER_SIZE];
            bufferPointer = bytesRead = 0;
        }

        public String readLine() throws IOException
        {
            byte[] buf = new byte[64]; // line length
            int cnt = 0, c;
            while ((c = read()) != -1)
            {
                if (c == '\n')
                    break;
                buf[cnt++] = (byte) c;
            }
            return new String(buf, 0, cnt);
        }

        public int nextInt() throws IOException
        {
            int ret = 0;
            byte c = read();
            while (c <= ' ')
                c = read();
            boolean neg = (c == '-');
            if (neg)
                c = read();
            do
            {
                ret = ret * 10 + c - '0';
            }  while ((c = read()) >= '0' && c <= '9');

            if (neg)
                return -ret;
            return ret;
        }

        public long nextLong() throws IOException
        {
            long ret = 0;
            byte c = read();
            while (c <= ' ')
                c = read();
            boolean neg = (c == '-');
            if (neg)
                c = read();
            do {
                ret = ret * 10 + c - '0';
            }
            while ((c = read()) >= '0' && c <= '9');
            if (neg)
                return -ret;
            return ret;
        }

        public double nextDouble() throws IOException
        {
            double ret = 0, div = 1;
            byte c = read();
            while (c <= ' ')
                c = read();
            boolean neg = (c == '-');
            if (neg)
                c = read();

            do {
                ret = ret * 10 + c - '0';
            }
            while ((c = read()) >= '0' && c <= '9');

            if (c == '.')
            {
                while ((c = read()) >= '0' && c <= '9')
                {
                    ret += (c - '0') / (div *= 10);
                }
            }

            if (neg)
                return -ret;
            return ret;
        }

        private void fillBuffer() throws IOException
        {
            bytesRead = din.read(buffer, bufferPointer = 0, BUFFER_SIZE);
            if (bytesRead == -1)
                buffer[0] = -1;
        }

        private byte read() throws IOException
        {
            if (bufferPointer == bytesRead)
                fillBuffer();
            return buffer[bufferPointer++];
        }

        public void close() throws IOException
        {
            if (din == null)
                return;
            din.close();
        }
    }


    public static void main(String[] args) throws IOException {
        Reader sc = new Reader();
        int k = sc.nextInt();
        int[][] buckets = new int[k][];
        long[] bucketSum = new long[k];
        Map<Integer, Integer> map = new HashMap<>(k * 10000);
        long target = 0;
        for (int i = 0; i < k; i++) {
            int n = sc.nextInt();
            int[] arr = new int[n];
            for (int j = 0; j < n; j++) {
                arr[j] = sc.nextInt();
                target += arr[j];
                map.put(arr[j], i);
                bucketSum[i] += arr[j];
            }
            buckets[i] = arr;
        }
        if ((target % k) != 0) {
            System.out.println("No");
            return;
        } else {
            target /= k;
        }

        int[] bitmask = new int[1 << (k )];
        Arrays.fill(bitmask, -1);


        for (int i = 0; i < k; i++) {
            for (int j = 0; j < buckets[i].length; j++) {
                int start = buckets[i][j];
                int next = (int) (target - bucketSum[i]) + start;

                Set<Integer> visited = new HashSet<>();
                Set<Integer> visitedBuckets = new HashSet<>();

                visited.add(start);
                visitedBuckets.add(i);
                int bitset = 1 << i;

                while (map.containsKey(next)) {
                    int bucket = map.get(next);
                    if (start == next) {
                        bitmask[bitset] = start;
                        break;
                    } else if (visited.contains(next)) {
                        break;
                    } else if (visitedBuckets.contains(bucket)) {
                        break;
                    }
                    visited.add(next);
                    visitedBuckets.add(bucket);
                    next = (int) (target - bucketSum[bucket]) + next;
                    bitset |= 1 << bucket;
                }
            }
        }

        boolean[] dp = new boolean[1 << (k ) ];
        Arrays.fill(dp, false);
        int[] build = new int[1 << k];
        Arrays.fill(build, -1);

        for (int i = 0; i < dp.length; i++) {
            dp[i] = bitmask[i] != -1;
        }
        for (int m = 0; m < (1 << k); m++) {
            if (!dp[m]) {
                for (int s = m; s != 0; s = (s - 1) & m) {
                    if (dp[s] && dp[(m ^ s)])   {
                        dp[m] = true;
                        build[m] = s;
                        break;
                    }
                }
            }
        }
        System.out.println(dp[dp.length - 1] ? "Yes" : "No");
        ArrayList<Integer> path = new ArrayList<>();
        rec(path, build, bitmask, (1 << k) - 1);

        int[] picked = new int[k];
        int[] out = new int[k];
        if (dp[dp.length - 1]) {
            for (int i : path) {
                int prev = i;
                int next = (int) (target - bucketSum[map.get(prev)]) + prev;
                picked[map.get(next)] = next;
                out[map.get(next)] = map.get(prev);
                while (next != i) {
                    int t = next;
                    next = (int) (target - bucketSum[map.get(next)]) + next;
                    prev = t;
                    out[map.get(next)] = map.get(prev);
                    picked[map.get(next)] = next;


                }
            }
            for (int i = 0; i < out.length; i++) {
                System.out.println((picked[i]) + " " + (out[i] + 1));
            }
        }
    }

    public static void rec(ArrayList<Integer> path, int[] build, int[] bitmask, int i) {
        if (!(i >= 0 && i < bitmask.length)) {
            return;
        }
        if (bitmask[i] != -1) {
            path.add(bitmask[i]);
        } else {
            rec(path, build, bitmask, build[i]);
            rec(path, build, bitmask, i ^ build[i]);
        }
    }
}

import java.io.*;
import java.util.*;

public class E implements Runnable {
	public static void main (String[] args) {new Thread(null, new E(), "_cf", 1 << 28).start();}

	HashMap<Integer, Integer> valToNode, nodeToVal, whichBox;
	int N, ptsTo[], cycleMask[], dfsStack[], tempList[];
	ArrayDeque<Integer> stack = new ArrayDeque<>();

	public void run() {
		FastScanner fs = new FastScanner();
		PrintWriter out = new PrintWriter(System.out);
		System.err.println("");

		valToNode = new HashMap<>();
		nodeToVal = new HashMap<>();
		whichBox = new HashMap<>();

		int K = fs.nextInt();
		int[][] vals = new int[K][], valToNode2 = new int[K][];
		long[] sums = new long[K];
		long total = 0;

		for(int i = 0; i < K; i++) {
			int size = fs.nextInt();
			vals[i] = new int[size];
			valToNode2[i] = new int[size];
			for(int j = 0; j < size; j++) {
				vals[i][j] = fs.nextInt();
				sums[i] += vals[i][j];
				valToNode2[i][j] = valToNode.size();
				valToNode.put(vals[i][j], valToNode.size());
				nodeToVal.put(valToNode.size()-1, vals[i][j]);
				whichBox.put(vals[i][j], i);
			}
			total += sums[i];
		}
		if(total % K != 0) {
			System.out.println("No");
			return;
		}
		long perGroup = total/K;

		N = valToNode.size();
		ptsTo = new int[N];
		for(int i = 0; i < K; i++) {
			for(int j = 0; j < vals[i].length; j++) {
				long newSum = perGroup - (sums[i]-vals[i][j]);
				if(newSum > (int)1e9 || newSum < (int)-1e9) continue;
				if(valToNode.containsKey((int)newSum)) {
					ptsTo[valToNode.get(vals[i][j])] = valToNode.get((int)newSum);
				}
				else ptsTo[valToNode.get(vals[i][j])] = -1;
			}
		}

		tempList = new int[N];
		dfsStack = new int[N];
		cycleMask = new int[N];

		for(int i = 0; i < K; i++) {
			for(int j = 0; j < vals[i].length; j++) {
				int node = valToNode.get(vals[i][j]);
				if(dfsStack[node] == 0) dfs(node);
			}
		}

		int[] goodMask = new int[1<<K];
		Arrays.fill(goodMask, -1); goodMask[0] = 0;
		for(int mask = 1; mask < goodMask.length; mask++) {
			int idx = Integer.numberOfTrailingZeros(Integer.lowestOneBit(mask));
			for(int i = 0; i < vals[idx].length; i++) {
				int node = valToNode2[idx][i];
				if(cycleMask[node] == mask) {
					goodMask[mask] = node;
					break;
				}
			}
		}

		int[] dp = new int[1<<K];
		Arrays.fill(dp, -1); dp[0] = 0;
		for(int mask = 1; mask < dp.length; mask++) {
			if(goodMask[mask] != -1) {
				dp[mask] = mask;
				continue;
			}
			for(int sub = mask; sub != 0; sub = (sub-1)&mask) {
				if(goodMask[sub] == -1) continue;
				int newMask = mask-sub;
				if(dp[newMask] == -1) continue;

				dp[mask] = sub;
				break;
			}
		}

		if(dp[dp.length-1] == -1) out.println("No");
		else {
			int[][] res = new int[K][2];
			for(int[] x : res) Arrays.fill(x, -1);
			int curMask = dp.length-1;
			while(curMask > 0) {
				int temp = dp[curMask];
				int curNode = goodMask[temp];

				while(temp > 0) {
					int curVal = nodeToVal.get(curNode), curBox = whichBox.get(curVal);
					res[curBox][0] = curVal;
					int goingTo = ptsTo[curNode], goingVal = nodeToVal.get(goingTo), goingBox = whichBox.get(goingVal);
					res[goingBox][1] = curBox;
					curNode = ptsTo[curNode];
					temp -= 1<<curBox;
				}

				curMask -= dp[curMask];
			}

			out.println("Yes");
			for(int i = 0; i < K; i++) {
				if(res[i][1] == -1) throw null;
				out.printf("%d %d\n", res[i][0], res[i][1]+1);
			}
		}

		out.close();
	}

	void dfs(int node) {
		dfsStack[node] = 1;
		stack.addLast(node);
		int goTo = ptsTo[node];
		if(goTo == -1) {
			while(!stack.isEmpty()) {
				cycleMask[stack.pollLast()] = -1;
			}
		}
		else {
			if(dfsStack[goTo] == 1) {
				int ptr = 0, mask = 0, conflict = 0;
				while(!stack.isEmpty()) {
					int now = stack.pollLast(), val = nodeToVal.get(now), box = whichBox.get(val);
					tempList[ptr++] = now;
					if((mask & (1<<box)) > 0) conflict = 1;
					mask |= 1<<box;

					if(now == goTo) break;
				}
				while(!stack.isEmpty()) {
					cycleMask[stack.pollLast()] = -1;
				}
				for(int i = 0; i < ptr; i++) {
					int now = tempList[i];
					if(conflict > 0) cycleMask[now] = -1;
					else cycleMask[now] = mask;
				}
			}
			else if(dfsStack[goTo] == 2) {
				while(!stack.isEmpty()) {
					cycleMask[stack.pollLast()] = -1;
				}
			}
			else {
				dfs(goTo);
			}
		}

		dfsStack[node] = 2;
	}

	class FastScanner {
		public int BS = 1<<16;
		public char NC = (char)0;
		byte[] buf = new byte[BS];
		int bId = 0, size = 0;
		char c = NC;
		double num = 1;
		BufferedInputStream in;

		public FastScanner() {
			in = new BufferedInputStream(System.in, BS);
		}

		public FastScanner(String s) {
			try {
				in = new BufferedInputStream(new FileInputStream(new File(s)), BS);
			}
			catch (Exception e) {
				in = new BufferedInputStream(System.in, BS);
			}
		}

		public char nextChar(){
			while(bId==size) {
				try {
					size = in.read(buf);
				}catch(Exception e) {
					return NC;
				}                
				if(size==-1)return NC;
				bId=0;
			}
			return (char)buf[bId++];
		}

		public int nextInt() {
			return (int)nextLong();
		}

		public long nextLong() {
			num=1;
			boolean neg = false;
			if(c==NC)c=nextChar();
			for(;(c<'0' || c>'9'); c = nextChar()) {
				if(c=='-')neg=true;
			}
			long res = 0;
			for(; c>='0' && c <='9'; c=nextChar()) {
				res = (res<<3)+(res<<1)+c-'0';
				num*=10;
			}
			return neg?-res:res;
		}

		public double nextDouble() {
			double cur = nextLong();
			return c!='.' ? cur:cur+nextLong()/num;
		}

		public String next() {
			StringBuilder res = new StringBuilder();
			while(c<=32)c=nextChar();
			while(c>32) {
				res.append(c);
				c=nextChar();
			}
			return res.toString();
		}

		public String nextLine() {
			StringBuilder res = new StringBuilder();
			while(c<=32)c=nextChar();
			while(c!='\n') {
				res.append(c);
				c=nextChar();
			}
			return res.toString();
		}

		public boolean hasNext() {
			if(c>32)return true;
			while(true) {
				c=nextChar();
				if(c==NC)return false;
				else if(c>32)return true;
			}
		}

		public int[] nextIntArray(int n) {
			int[] res = new int[n];
			for(int i = 0; i < n; i++) res[i] = nextInt();
			return res;
		}

	}

}

