			for(int m = 0; m < (1<<n); m++) {
				dp[m] = new ArrayList<cycle>();
				if(masktocyc[m] != null) {
					dp[m].add(masktocyc[m]);
					continue;
				}
				for(int s = m; s > 0; s = (s - 1) & m) {
