							used = mp.bitadd(used,k);
							now = next;
							see = k;
						}
					}
				}
				if(f) {
					dp[mp.bitadd(used,i)] = true;
					first[mp.bitadd(used,i)] = a;
				}
			}
		}

		dp[0] = true;
		for(int i=1;i<(1<<N);i++) {
			for(int j=i;j>0;j=(j-1)&i) {
				if(dp[i^j]&&dp[j]) {
					dp[i]=true;
