            }
            tar += sum[i];
        }
        if (tar % k != 0) { System.out.println("No"); return; }
        tar /= k;
        works = new HashMap<>();
        for (int i = 0; i < k; i++)
        {
            outer: for (int j = 0; j < arr[i].length; j++)
            {
                long val = arr[i][j];
