    boolean[] done, yes;

    long r(int mask)
    {
        if (done[mask]) return dp[mask];
        done[mask] = true;
        for (int s = mask; s != 0; s = (s-1) & mask)
            if (works.keySet().contains(s))
            {
                int tempMask = mask;
                for (int i = 0; i < 16; i++)
                    if ((s & (1 << i)) != 0)
                        tempMask ^= 1 << i;
                r(tempMask);
                if (yes[tempMask])
                {
                    yes[mask] = true;
                    return dp[mask] = (((long)s) << 32) + tempMask;
                }
            }
        return 0;
    }

